         />

         <AnimatePresence mode="popLayout">
           {isEditing ? (
             <motion.button
               key="done"
-              initial={{ opacity: 0, filter: 'blur(4px)', scale: 0 }}
-              animate={{ opacity: 1, filter: 'blur(0px)', scale: 1 }}
-              exit={{ opacity: 0, filter: 'blur(4px)', scale: 0 }}
+              initial={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
+              animate={{ filter: "blur(0px)", opacity: 1, scale: 1 }}
+              exit={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
               layout="position"
               onClick={handleSave}
               transition={{
-                type: 'spring',
                 bounce: 0,
                 duration: 0.4,
+                type: "spring",
               }}
               className="rounded-full bg-black p-1 text-white transition-colors dark:bg-zinc-100 dark:text-zinc-950"
             >
               <Check size={26} />
             </motion.button>
           ) : (
             <motion.button
               key="edit"
-              initial={{ opacity: 0, filter: 'blur(4px)', scale: 0 }}
-              animate={{ opacity: 1, filter: 'blur(0px)', scale: 1 }}
-              exit={{ opacity: 0, filter: 'blur(4px)', scale: 0 }}
+              initial={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
+              animate={{ filter: "blur(0px)", opacity: 1, scale: 1 }}
+              exit={{ filter: "blur(4px)", opacity: 0, scale: 0 }}
               layout="position"
               onClick={handleEdit}
               transition={{
-                type: 'spring',
                 bounce: 0,
                 duration: 0.4,
+                type: "spring",
               }}
               className="rounded-full bg-[#F0EFF6] p-1 text-[#696871] transition-colors dark:bg-zinc-800 dark:text-zinc-400 hover:dark:bg-zinc-700"
             >
               <BiSolidPencil size={26} />
             </motion.button>
           )}
         </AnimatePresence>
       </div>
     </motion.div>
   );
 };

